class Solution:
    def shortestSubstrings(self, arr: List[str]) -> List[str]:
        from collections import defaultdict

        # Step 1: Collect all substrings from all strings except the current one
        substr_count = defaultdict(int)
        n = len(arr)
        for i in range(n):
            for j in range(len(arr[i])):
                for k in range(j + 1, len(arr[i]) + 1):
                    substr = arr[i][j:k]
                    substr_count[substr] += 1

        # Step 2: For each string, find the shortest and lexicographically smallest unique substring
        result = []
        for s in arr:
            min_len = float('inf')
            candidates = []
            for i in range(len(s)):
                for j in range(i + 1, len(s) + 1):
                    substr = s[i:j]
                    if substr_count[substr] == 1:
                        candidates.append(substr)
            if candidates:
                result.append(min(candidates))
            else:
                result.append("")
        return result
